import React, { Component } from 'react';



export default class App extends Component {

  state = {
      direction: '',
      points: [],
      started: false,
      moveID: null,
      createID: null,
      hit: null,
      score: 0,
      message: '',
  }

  audio = new Audio('https://sndup.net/32gv/music1.mp3')

  messages = [
      'uSe ARrows to CONTROL This LOWRider',
      'FoLloW thE BeAt',
      'You AweSoMe',
      'KeEp IT Up!',
      'yoU are tRuE OG'
  ]

  loopPoints = () => {
      let directions = ['up', 'right', 'down', 'left']
      this._createPoint(directions[Math.floor(Math.random()*3)])
      let _createID = setTimeout(() => {
          this.loopPoints();
      },  Math.round(Math.random())*660 + 670);
      this.setState({createID: _createID})
  }

  clearPoints() {
      clearInterval(this.state.createID)
      this.setState({points: []})
  }

  _handlePoints = (isSetPlay) => {
      if (!isSetPlay) {
          this._stopPoints()
      }
      else {
          this._startPoints()
      }
  }

  _createPoint = (arrow) => {
      this.setState(({points}) => {
          return {
              points: [...points, {pos: 0, arrow: arrow, status: 0}]
          }
      })
  }

  _movePoints = () => {
      this.setState(({points}) => {
          let _points = points.map(el => ({ ...el, pos: el.pos + 1 }))
          return {
              points: _points,
          }
      })
  }

  _startPoints = () => {
      this.audio.play().then(() => {
          this.setMessage();
          this.loopPoints()
          this.setState({moveID: setInterval(this._movePoints, 90)})
      }).catch()
  }

  _stopPoints = () => {
      this.clearPoints()
      this.clearScore()
      clearInterval(this.state.moveID)
      this.audio.pause()
      this.audio.currentTime = 0
  }

  handleKeydown() {
      document.addEventListener("keydown", (e) => {
          if (e.repeat) return
          this.setDirection(e.code)
      }, false);
      document.addEventListener("keyup",(e) => {
          setTimeout(() => this.setDirection(), 200)
      });
  }

  handlePlay = () => {
      this.setState(({started}) => {
          return {
              started: !started
          }
      }, () => {
          this._handlePoints(this.state.started)
      })
  }

  setButtonText() {
      return this.state.started ? 'Stop' : 'Start'
  }

  setIndicator = () => {
      switch (this.state.hit) {
          case false:
              return 'bad'
          case true:
              return 'good'
          default:
              return null
      }
  }

  checkScore(pos) {
      if (pos === -1) return 0
      if (pos === 50) return 300
      if (pos < 49 || pos > 51) return 100
      else return 200
  }

  setScore(pos) {
     this.setState({score: this.state.score + this.checkScore(pos)})
  }

  clearScore() {
      this.setState({score: 0, message: ''})
      clearInterval(this.msgInterval)
  }

  checkHit(dir) {
      if (!this.state.started) return
      const matchedPoint = this.state.points.find(el => (el.pos >= 47  && el.pos <= 53) &&
                                                         dir === el.arrow &&
                                                         el.status !== 1)
      let position = matchedPoint ? matchedPoint.pos : -1
      this.setState({hit: !!matchedPoint})
      this.setScore(position)
  }

  setDirection(code) {
      let arrows = [
          'ArrowUp',
          'ArrowRight',
          'ArrowDown',
          'ArrowLeft',
      ]
      if (arrows.includes(code)) {
          let direction = code.replace('Arrow', '').toLowerCase()
          this.setState({ direction }, () => {
              this.checkHit(direction)
          });
      }
      else if (code === undefined) {
          this.setState({
              direction: null,
              hit: null
          })
      }
  }

  setMessage() {
      this.msgInterval = setInterval(() => {
          this.setState({message: this.messages[Math.floor(Math.random()*(this.messages.length - 1))]})
      }, 4000)
  }

  componentDidMount() {
      this.handleKeydown()
      this.audio.onended = () => {
          this.handlePlay()
      }
  }

  componentWillUnmount() {
      clearInterval(this.msgInterval)
  }

    render() {

      const {score, direction, points, message, started} = this.state

      return (
        <div className={`app ${started ? 'playing' : ''}`}>
          <button className="btn" onClick={this.handlePlay}>{this.setButtonText()}</button>
          <div className={`score`}>{score}</div>
            <div className={`car ${direction}`}>
                <span>{message}</span>
            </div>
          <Points points={points} hitCheck={this.setIndicator} started={started}/>
        </div>
        )

  };
}

const Points = ({points, hitCheck}) => {
    const elements = points.map((el, index) => {
        return <Point key={`point-${index}`} point={el} />
    })

    return (
        <div className={`line ${hitCheck()}`}>
            {elements}
        </div>
    )
}

const Point = ({point}) => {
    return (
        <div className={`point point-${point.arrow}`} style={{left: `${point.pos}%`}}/>
    )
}
